const row = $input.first()?.json ?? {};
const moved = Number(row.moved_row_count ?? 0);
const currentSeason = row.current_season ?? null;
const oldest = row.oldest_moved_season ?? null;
const newest = row.newest_moved_season ?? null;

return [{
  json: {
    current_season: currentSeason,
    moved_row_count: moved,
    message: moved
      ? `Moved ${moved} raw_members rows for seasons ${oldest} to ${newest} into raw_members_historical.`
      : `No raw_members rows matched seasons earlier than ${currentSeason}.`,
    oldest_moved_season: oldest,
    newest_moved_season: newest,
  },
}];
